55	const BASE_PREMIUM: Record<string, number> = {
56	  sword: 100,
57	  amulet: 60,
58	  staff: 80,
59	  potion: 40,
60	  rune: 25,
61	};
62	
63	const COMPONENT_PRICE = 25;
64	const BLOCK_SIZE = 3;
65	const BLOCK_PRICE = 60;
66	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
67	
68	const INITIAL_ASSESSMENT_RATE = 0.1;
69	const CURSE_SURCHARGE_RATE = 0.5;
70	const PROCESSING_FEE = 5;
71	const FLOAT_PRECISION_DIGITS = 6;
72	
73	const itemOwnBase = (item: Item): number => {
74	  return COMPONENT_TYPES.has(item.type)
75	    ? COMPONENT_PRICE
76	    : BASE_PREMIUM[item.type];
77	};
78	
79	const itemSurcharge = (item: Item): number => {
80	  return item.cursed ? CURSE_SURCHARGE_RATE * itemOwnBase(item) : 0;
81	};
82	
83	const componentBase = (count: number): number => {
84	  return count === BLOCK_SIZE ? BLOCK_PRICE : count * COMPONENT_PRICE;
85	};
86	
87	const countByType = (items: Item[]): Map<string, number> => {
88	  const counts = new Map<string, number>();
89	  for (const item of items) {
90	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
91	  }
92	  return counts;
93	};
94	
95	const itemBaseTotal = (items: Item[]): number => {
96	  let total = 0;
97	  for (const [type, count] of countByType(items)) {
98	    total += COMPONENT_TYPES.has(type)
99	      ? componentBase(count)
100	      : BASE_PREMIUM[type] * count;
101	  }
102	  return total;
103	};
104	
105	const quotePremium = (step: QuoteStep): number => {
106	  const policyBase = itemBaseTotal(step.items);
107	  const surcharges = step.items.reduce(
108	    (sum, item) => sum + itemSurcharge(item),
109	    0,
110	  );
111	  const initialAssessment = INITIAL_ASSESSMENT_RATE * policyBase;
112	  const premium = policyBase + surcharges + initialAssessment + PROCESSING_FEE;
113	  return Math.ceil(Number(premium.toFixed(FLOAT_PRECISION_DIGITS)));
114	};
115	
116	export const runScenario = (scenario: Scenario): ScenarioResult => {
117	  return {
118	    results: scenario.steps.map((step) => ({
119	      premium: quotePremium(step as QuoteStep),
120	    })),
121	  };
122	};
